import { useNavigation } from '@react-navigation/native';
import {
  Box,
  Button,
  LimitCard,
  QuickAccess,
  SeparatorHorizontal,
  StatusValues,
  Text,
  TextIcon,
} from '@semparar/design-system-app';
import React from 'react';
import { eventSelectContent } from '~/constants/functions';
import { moment } from '../../../services/moment';
import {
  formatToCurrency,
  transformInvoiceToPattern,
} from '../../../utils/functions';
import { InvoiceStatusViewProps } from './Models';
import { Container } from './styles';
import { TextIconRewardProgram } from '../../molecules/TextIconRewardProgram';

export const InvoiceStatusView = ({
  invoiceStatusObject,
  setShowValue,
  showValue,
  productsReducer,
  carrouselItems,
  invoiceData,
  cashback,
  handleNavigateToCashback,
  invoiceType,
  isAutoDebt,
  loadingProducts,
  loadingCashback,
}: InvoiceStatusViewProps) => {
  const navigation = useNavigation();
  return (
    <Container>
      <StatusValues
        highlightTag
        hasButtonSecundarySmall={invoiceStatusObject?.hasPaymentBtn}
        textButtonSecondarySmall="Exibir fatura"
        {...invoiceStatusObject}
        onPressSecundarySmall={() => {
          eventSelectContent({
            content_type: 'cta',
            content_id: 'ver_fatura',
            location_1: 'autosservico',
            location_2: 'spmais',
            location_3: 'home_spmais',
          });
          navigation.navigate('InvoiceCard', {
            dueDate: invoiceData.Vencimento,
            date: moment().toISOString(),
            analytics: {
              screen_name: 'spmais',
              screen_class: 'home_spmais',
              screen_bussines: 'autosservico',
              screen_info: {
                location_1: 'autosservico',
                location_2: 'spmais',
                location_3: 'home_spmais',
              },
            },
          });
        }}
        value={formatToCurrency(invoiceData.Valor)}
        showValue={showValue}
        valueColor="INTENSE_COLOR_01"
        colorDotIcon="BRAND_COMPLEMENT_02"
        colorDate="INTENSE_COLOR_01"
      />
      <Box width="100%" direction align="center" mt="quark">
        <Text
          testID="textInvoiceType"
          maxWidth="100%"
          maxFontSizeMultiplier={1.6}
          numberOfLines={1}
          type="paragraphMD"
          color="INTENSE_COLOR_02"
        >
          {invoiceType === 'default' ? 'Fechamento ' : 'Vencimento '}
          {moment(
            invoiceType === 'default'
              ? invoiceData.DataDeCorte
              : invoiceData.VencimentoOriginal,
          ).format('DD/MM')}
        </Text>
      </Box>
      {(invoiceStatusObject?.hasInstallmentBtn ||
        invoiceStatusObject?.hasPaymentOptionBtn) && (
        <Box direction justify="space-between" mt="xxxs">
          <Box width="100%">
            <Button
              testID="btnInvoiceStatusPayInvoice"
              type="primaryLarge"
              text="Pagar fatura"
              onPress={() => {
                eventSelectContent({
                  content_type: 'cta',
                  content_id: 'pagar_fatura',
                  location_1: 'autosservico',
                  location_2: 'spmais',
                  location_3: 'home_spmais',
                });
                navigation.navigate('PayInvoice', {
                  payment: transformInvoiceToPattern(invoiceData),
                  analytics: {
                    screen_name: 'spmais',
                    screen_class: 'home_spmais',
                    screen_bussines: 'autosservico',
                    screen_info: {
                      location_1: 'autosservico',
                      location_2: 'spmais',
                      location_3: 'home_spmais',
                    },
                  },
                });
              }}
            />
          </Box>
        </Box>
      )}

      <LimitCard
        limitTotal={productsReducer?.Limite}
        limitUsed={productsReducer?.Limite - productsReducer?.LimiteDisponivel}
        textLimitUsed="Limite utilizado"
        textLimitValue="DisponĂ­vel"
        mt="xs"
        hideBgColor
        showLimitAvailable={showValue}
        showLimitUse={showValue}
        hidePadding
        bgBarColor="INTENSE_COLOR_05"
        isLoading={loadingProducts}
      />

      {invoiceData.MelhorDiaCompra ? (
        <Box width="100%" direction align="center" mt="xxs">
          <Text
            testID="textInvoiceStatusBestDayToBuy"
            maxWidth="100%"
            maxFontSizeMultiplier={1.6}
            numberOfLines={1}
            type="paragraphMD"
            color="INTENSE_COLOR_02"
          >
            Melhor dia de compra:{' '}
            {moment(invoiceData.MelhorDiaCompra).format('DD/MM')}
          </Text>
        </Box>
      ) : null}

      <SeparatorHorizontal bgColor="INTENSE_COLOR_05" height={1} mt="xs" />
      <TextIconRewardProgram showValue={showValue} />
      {isAutoDebt && (
        <TextIcon
          mt="xxs"
          type="price"
          description="DĂ©bito em conta ativo"
          iconName="icon-debit-account"
          iconSize="sm"
          bgIconColor="transparent"
          testID="textInvoiceStatusAutoDebt"
          iconColor="BRAND_COMPLEMENT_03"
          textColor="BRAND_COMPLEMENT_03"
          priceValueColor="BRAND_COMPLEMENT_03"
          bulletColor="BRAND_COMPLEMENT_03"
        />
      )}
      <QuickAccess type="magenta" data={carrouselItems} mt="xs" themes="dark" />
    </Container>
  );
};

import type { RefObject } from 'react';
import type { WebViewProps } from 'react-native-webview';
import type { WebViewErrorEvent } from 'react-native-webview/lib/WebViewTypes';

export type { WebViewProps, WebViewErrorEvent };

export interface WebViewScreenProps {
  uri: string;
  title: string;
  webViewRef: RefObject<WebViewProps | null>;
  onBackPress: () => void;
  onError: (event: WebViewErrorEvent) => void;
  onRetry: () => void;
}

import { PropsItemsTransactionsList } from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';

import theme from '../../styles/theme';

export class DataGroupedByDayMapper {
  public static map(
    data?: PropsItemsTransactionsList[],
  ): propsItemsListCardTransition[] {
    if (!data) return [];

    const getColors = (color?: string) => {
      if (!color) return undefined;

      return (
        Object.entries(theme.colors).find(
          ([_, value]) => value === color,
        )?.[0] ?? color
      );
    };

    return data.flatMap(({ date: label, items }) =>
      items?.map((item, index) => ({
        label,
        showLabel: index === 0,
        type: 'default',
        leftIcon: item.icon,
        leftIconColor: getColors(item.iconColor),
        title: item.title,
        titleColor: getColors(item.titleColor),
        value: item.value,
        valueColor: getColors(item.valueColor),
        descriptionSecondary: item.description,
        descriptionSecondaryColor: getColors(item.descriptionColor),
        bgColor: getColors(item.bgColor),
        showBackgroundLeftIcon: false,
        showIcon: true,
        showRightIcon: false,
        lineThrough: item.icon === 'icon-corner-up-left',
      })),
    ) as propsItemsListCardTransition[];
  }
}

